import{_ as s,o as a,c as t,ak as o}from"./chunks/framework.oFDsBAuP.js";const u=JSON.parse('{"title":"鉴权体系说明（Auth）","description":"","frontmatter":{"title":"鉴权体系说明（Auth）","source":"https://docs.newapi.pro/zh/docs/api/management/auth","syncedAt":"2026-05-10T11:17:15.254Z"},"headers":[],"relativePath":"api/management/auth.md","filePath":"api/management/auth.md"}'),n={name:"api/management/auth.md"};function i(r,e,p,c,l,d){return a(),t("div",null,[...e[0]||(e[0]=[o('<p>管理接口</p><p>后台管理接口鉴权方式与权限级别说明</p><p>后台管理接口采用多级鉴权机制，常见为：<strong>公开</strong>、<strong>用户</strong>、<strong>管理员</strong>、<strong>Root</strong>。</p><h3 id="session" tabindex="-1"><a href="#session">Session</a> <a class="header-anchor" href="#session" aria-label="Permalink to &quot;[Session](#session)&quot;">​</a></h3><p>通过登录接口获取 Session：</p><ul><li><code>POST /api/user/login</code></li></ul><h3 id="access-token-推荐" tabindex="-1"><a href="#access-token推荐">Access Token（推荐）</a> <a class="header-anchor" href="#access-token-推荐" aria-label="Permalink to &quot;[Access Token（推荐）](#access-token推荐)&quot;">​</a></h3><p>在请求头中携带：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Authorization: Bearer {token}</span></span></code></pre></div><p>Token 可在「个人设置 - 安全设置 - 系统访问令牌」中生成。</p><p>部分接口要求携带用户标识请求头：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>New-Api-User: {user_id}</span></span></code></pre></div><p>其中 <code>{user_id}</code> 必须与当前登录用户匹配。</p><ul><li><strong>公开（Public）</strong>：无需鉴权</li><li><strong>用户（User）</strong>：需要登录或 Access Token</li><li><strong>管理员（Admin）</strong>：需要管理员权限</li><li><strong>Root</strong>：最高权限</li></ul><p>这篇文档对您有帮助吗？</p><p>最后更新于</p><hr><blockquote><p><strong>来源</strong>：<a href="https://docs.newapi.pro/zh/docs/api/management/auth" target="_blank" rel="noreferrer">官方文档</a>（New API）。本站为离线整理副本，如有出入以官方为准。</p></blockquote>',18)])])}const g=s(n,[["render",i]]);export{u as __pageData,g as default};
